// Kernel: extract (from Infrastructure File 1)
__kernel void extract_kernel(
    long d_Ne,
    fp *d_I)
{
    int bx = get_block_id(0);
    int tx = get_thread_id(0);
    int ei = (bx * NUMBER_THREADS) + tx;

    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * 255;
    }
}

// Kernel: compress (from Infrastructure File 2 - named compress in file, but wrapper expects compress_kernel)
__kernel void compress_kernel(
    long d_Ne,
    fp *d_I)
{
    int bx = get_block_id(0);
    int tx = get_thread_id(0);
    int ei = (bx * NUMBER_THREADS) + tx;

    if (ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / 255);
    }
}

// Kernel: prepare (from Infrastructure File 4 - wrapper expects prepare_kernel)
__kernel void prepare_kernel(
    long d_Ne,
    fp *d_I,
